-- Load the color theme
-- Source: ~/.config/hypr/themes/catppuccin/mocha.conf — convert this file to Lua and ensure it is on Lua's package.path.
local colors = require("themes.catppuccin-mocha")

hl.curve("easeOutQuint", { type = "bezier", points = { { 0.23, 1 }, { 0.32, 1 } } })
hl.curve("easeInOutCubic", { type = "bezier", points = { { 0.65, 0.05 }, { 0.36, 1 } } })
hl.curve("linear", { type = "bezier", points = { { 0, 0 }, { 1, 1 } } })
hl.curve("almostLinear", { type = "bezier", points = { { 0.5, 0.5 }, { 0.75, 1.0 } } })
hl.curve("quick", { type = "bezier", points = { { 0.15, 0 }, { 0.1, 1 } } })
hl.animation({
  leaf = "global",
  enabled = true,
  speed = 10,
  bezier = "default",
})
hl.animation({
  leaf = "border",
  enabled = true,
  speed = 5.39,
  bezier = "quick",
})
hl.animation({ leaf = "windows", enabled = true, speed = 4.1, bezier = "easeInOutCubic", style = "gnomed" })
